import { tscdEndpoint } from './endpoint';
import type {
  CreateFixedAssetDto,
  UpdateFixedAssetDto,
  FixedAssetFilter,
  CreateDisposalDto,
  CreateAdjustmentDto,
  CreateTransferDto,
  SuspendDepreciationDto,
} from './models';

export const tscdService = {
  getAssets: (f?: FixedAssetFilter) => tscdEndpoint.getAssets(f),
  searchAssets: (f: FixedAssetFilter) => tscdEndpoint.searchAssets(f),
  getAsset: (id: string) => tscdEndpoint.getAsset(id),
  createAsset: (dto: CreateFixedAssetDto) => tscdEndpoint.createAsset(dto),
  updateAsset: (id: string, dto: UpdateFixedAssetDto) => tscdEndpoint.updateAsset(id, dto),
  getDisposals: () => tscdEndpoint.getDisposals(),
  createDisposal: (dto: CreateDisposalDto) => tscdEndpoint.createDisposal(dto),
  createAdjustment: (dto: CreateAdjustmentDto) => tscdEndpoint.createAdjustment(dto),
  createTransfer: (dto: CreateTransferDto) => tscdEndpoint.createTransfer(dto),
  suspendDepreciation: (dto: SuspendDepreciationDto) => tscdEndpoint.suspendDepreciation(dto),
  getDepreciation: (m: number, y: number) => tscdEndpoint.getDepreciation(m, y),
  runDepreciation: (m: number, y: number) => tscdEndpoint.runDepreciation(m, y),
  postDepreciation: (m: number, y: number) => tscdEndpoint.postDepreciation(m, y),
  getDepreciationDocuments: (m: number, y: number) => tscdEndpoint.getDepreciationDocuments(m, y),
};
